INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('balanced-binary-tree', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"unvisited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"goal":"|leftH - rightH| <= 1 at every node"},"status":"Determine if the tree is height-balanced: every node''s two subtrees differ in height by at most 1."}'::jsonb),
('balanced-binary-tree', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"unvisited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"approach":"post-order DFS","trick":"return -1 on imbalance"},"status":"Bottom-up DFS: compute height of each subtree, short-circuit with -1 if any subtree is unbalanced."}'::jsonb),
('balanced-binary-tree', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"unvisited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Each node visited once; recursion stack bounded by tree height h."}'::jsonb),
('balanced-binary-tree', 4, 'Enter root (3)', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"current"},{"id":"b","value":9,"state":"unvisited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"call":"dfs(3)"},"status":"Recurse into left (9) first, then right (20)."}'::jsonb),
('balanced-binary-tree', 5, 'Leaf 9: height 1', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"current"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"dfs(9)":"1"},"status":"Leaf: left=0, right=0, |diff|=0. Return 1."}'::jsonb),
('balanced-binary-tree', 6, 'Enter 20', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"current"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"call":"dfs(20)"},"status":"Recurse into 15 and 7."}'::jsonb),
('balanced-binary-tree', 7, 'Leaf 15: height 1', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"current"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"dfs(15)":"1"},"status":"Balanced leaf. Return 1."}'::jsonb),
('balanced-binary-tree', 8, 'Leaf 7: height 1', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"dfs(7)":"1"},"status":"Balanced leaf. Return 1."}'::jsonb),
('balanced-binary-tree', 9, '20: height 2, balanced', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"dfs(20)":"2"},"status":"|1-1|=0 OK. Return 1 + max(1,1) = 2."}'::jsonb),
('balanced-binary-tree', 10, 'Root check: |1-2|=1', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"current"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"leftH":"1","rightH":"2","diff":"1"},"status":"Difference is 1, within allowance."}'::jsonb),
('balanced-binary-tree', 11, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"dfs(3)":"3"},"status":"No node violated the height property. Root height = 3."}'::jsonb),
('balanced-binary-tree', 12, 'Result: true', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"answer":"true"},"status":"Tree is balanced."}'::jsonb),
('balanced-binary-tree', 13, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Post-order DFS verifies balance in O(n) with O(h) stack."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('binary-tree-right-side', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":5,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"goal":"rightmost value per level"},"status":"Return values visible looking from the right: the last node at each depth."}'::jsonb),
('binary-tree-right-side', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":5,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"approach":"BFS level order"},"status":"BFS: at each level, the last dequeued node is the rightmost visible one."}'::jsonb),
('binary-tree-right-side', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":5,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"time":"O(n)","space":"O(w)"},"status":"O(n) over all nodes, O(w) queue width."}'::jsonb),
('binary-tree-right-side', 4, 'Init queue with root', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"current"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":5,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[1]","result":"[]"},"status":"Start BFS with root."}'::jsonb),
('binary-tree-right-side', 5, 'Level 0: rightmost=1', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":5,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[2,3]","result":"[1]"},"status":"Only one node at level 0 — record 1."}'::jsonb),
('binary-tree-right-side', 6, 'Dequeue 2 (not last)', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"current"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":5,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[3,5]","level_size":"2"},"status":"Still one more node at this level (3). Do not record yet."}'::jsonb),
('binary-tree-right-side', 7, 'Dequeue 3 — rightmost of level 1', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"current"},{"id":"d","value":5,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[5,4]","result":"[1,3]"},"status":"Last node at level 1. Record 3."}'::jsonb),
('binary-tree-right-side', 8, 'Dequeue 5 (not last)', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"},{"id":"d","value":5,"state":"current"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[4]"},"status":"One more to come this level."}'::jsonb),
('binary-tree-right-side', 9, 'Dequeue 4 — rightmost of level 2', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"},{"id":"d","value":5,"state":"visited"},{"id":"e","value":4,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[]","result":"[1,3,4]"},"status":"Last of level 2. Record 4."}'::jsonb),
('binary-tree-right-side', 10, 'Queue empty — terminate', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"},{"id":"d","value":5,"state":"visited"},{"id":"e","value":4,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[]"},"status":"All levels processed."}'::jsonb),
('binary-tree-right-side', 11, 'Result', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"},{"id":"d","value":5,"state":"visited"},{"id":"e","value":4,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"answer":"[1,3,4]"},"status":"Right view assembled."}'::jsonb),
('binary-tree-right-side', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"},{"id":"d","value":5,"state":"visited"},{"id":"e","value":4,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"time":"O(n)","space":"O(w)"},"status":"One BFS pass; last node of every level = right view."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('combination-sum-ii', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"candidates":"[1,2,2,2,5] (sorted)","target":"5"},"status":"Find unique combinations summing to 5; each number used at most once."}'::jsonb),
('combination-sum-ii', 2, 'Approach', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"approach":"sorted + DFS backtracking","dedup":"skip nums[i]==nums[i-1] at same depth"},"status":"Sort, then DFS. Skip duplicates at the same recursion depth to avoid repeated combos."}'::jsonb),
('combination-sum-ii', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(2^n)","space":"O(n)"},"status":"Up to 2^n subsets, but pruning cuts most branches."}'::jsonb),
('combination-sum-ii', 4, 'Root: start(idx=0, path=[], rem=5)', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"current"}],"edges":[],"hashmap":{"path":"[]","remaining":"5"},"status":"Begin DFS from index 0."}'::jsonb),
('combination-sum-ii', 5, 'Pick 1 (idx 0)', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":1,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"}],"hashmap":{"path":"[1]","remaining":"4"},"status":"Take first 1. Recurse from idx=1."}'::jsonb),
('combination-sum-ii', 6, 'Pick 2 (idx 1): path=[1,2]', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"b","side":"left"}],"hashmap":{"path":"[1,2]","remaining":"2"},"status":"Continue deeper."}'::jsonb),
('combination-sum-ii', 7, 'Pick 2 (idx 2): path=[1,2,2] sum=5', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":2,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"b","side":"left"},{"parent":"b","child":"c","side":"left"}],"hashmap":{"path":"[1,2,2]","remaining":"0","found":"[1,2,2]"},"status":"Hit target — record combination."}'::jsonb),
('combination-sum-ii', 8, 'Backtrack to idx=1, skip dup 2s', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":1,"state":"current"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":2,"state":"visited"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"b","side":"left"},{"parent":"b","child":"c","side":"left"}],"hashmap":{"note":"indices 2,3 same value at same depth as idx 1 — skip"},"status":"Deduplicate sibling 2s."}'::jsonb),
('combination-sum-ii', 9, 'Try 5 (idx 4): 1+5=6 > 5 prune', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":1,"state":"visited"},{"id":"d","value":5,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"d","side":"right"}],"hashmap":{"path":"[1,5]","remaining":"-1"},"status":"Overflow. Prune branch."}'::jsonb),
('combination-sum-ii', 10, 'Backtrack to root; try 2 (idx 1)', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"current"},{"id":"e","value":2,"state":"current"}],"edges":[{"parent":"r","child":"e","side":"right"}],"hashmap":{"path":"[2]","remaining":"3"},"status":"Skip idx 0 (already explored); start fresh from 2."}'::jsonb),
('combination-sum-ii', 11, 'No 3 available — branch fails', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"e","value":2,"state":"visited"}],"edges":[{"parent":"r","child":"e","side":"right"}],"hashmap":{"tried":"[2,2,2] sum=6 prune","also":"[2,5] sum=7 prune"},"status":"All deeper branches over target or dedup-skipped."}'::jsonb),
('combination-sum-ii', 12, 'Result', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":2,"state":"visited"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"b","side":"left"},{"parent":"b","child":"c","side":"left"}],"hashmap":{"answer":"[[1,2,2],[5]]"},"status":"Two unique combos. The [5] singleton found when starting at idx=4."}'::jsonb),
('combination-sum-ii', 13, 'Return + Recap', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"time":"O(2^n)","space":"O(n)"},"status":"Sort + DFS with same-depth dedup and prune-on-overflow."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('construct-from-preorder-inorder', 1, 'Problem Setup', '{"type":"tree","nodes":[],"edges":[],"hashmap":{"preorder":"[3,9,20,15,7]","inorder":"[9,3,15,20,7]"},"status":"Rebuild tree from preorder + inorder. Preorder[0] is always the root."}'::jsonb),
('construct-from-preorder-inorder', 2, 'Approach', '{"type":"tree","nodes":[],"edges":[],"hashmap":{"idx":"{9:0, 3:1, 15:2, 20:3, 7:4}"},"status":"Hash inorder index. For each preorder[i], locate its inorder position to split left/right subtree."}'::jsonb),
('construct-from-preorder-inorder', 3, 'Complexity', '{"type":"tree","nodes":[],"edges":[],"hashmap":{"time":"O(n)","space":"O(n)"},"status":"Each preorder element becomes a node in O(1) with the index map."}'::jsonb),
('construct-from-preorder-inorder', 4, 'Root = preorder[0] = 3', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"current"}],"edges":[],"hashmap":{"inorder_pos(3)":"1","left":"[9]","right":"[15,20,7]"},"status":"3 is the root. Inorder splits into left=[9] and right=[15,20,7]."}'::jsonb),
('construct-from-preorder-inorder', 5, 'Left subtree: preorder next=9', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"}],"hashmap":{"inorder_pos(9)":"0","left":"[]","right":"[]"},"status":"9 is a leaf — no elements flanking it in inorder."}'::jsonb),
('construct-from-preorder-inorder', 6, 'Right subtree root: preorder next=20', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"inorder_pos(20)":"3","left":"[15]","right":"[7]"},"status":"20 splits inorder[2..4] into left=[15] and right=[7]."}'::jsonb),
('construct-from-preorder-inorder', 7, 'Attach 15 as left of 20', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"}],"hashmap":{"inorder_pos(15)":"2"},"status":"15 is a leaf."}'::jsonb),
('construct-from-preorder-inorder', 8, 'Attach 7 as right of 20', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"inorder_pos(7)":"4"},"status":"7 is a leaf."}'::jsonb),
('construct-from-preorder-inorder', 9, 'Preorder pointer past end', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"preIdx":"5 / 5"},"status":"All preorder elements placed."}'::jsonb),
('construct-from-preorder-inorder', 10, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"status":"done"},"status":"Recursion unwinds to root."}'::jsonb),
('construct-from-preorder-inorder', 11, 'Result', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"root":"3"},"status":"Tree reconstructed."}'::jsonb),
('construct-from-preorder-inorder', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"time":"O(n)","space":"O(n)"},"status":"Preorder drives roots; inorder hashmap splits subtrees."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('diameter-binary-tree', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":4,"state":"unvisited"},{"id":"e","value":5,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"goal":"longest path (edges) between any two nodes"},"status":"Find the maximum number of edges on any path in the tree."}'::jsonb),
('diameter-binary-tree', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":4,"state":"unvisited"},{"id":"e","value":5,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"approach":"post-order DFS","update":"best = max(best, L+R)"},"status":"Each node: diameter through it = leftHeight + rightHeight. Track global max."}'::jsonb),
('diameter-binary-tree', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":4,"state":"unvisited"},{"id":"e","value":5,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Single post-order pass."}'::jsonb),
('diameter-binary-tree', 4, 'Init best=0, enter root', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"current"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":4,"state":"unvisited"},{"id":"e","value":5,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"best":"0"},"status":"Call dfs(1)."}'::jsonb),
('diameter-binary-tree', 5, 'Leaf 4: h=0', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":4,"state":"current"},{"id":"e","value":5,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"h(4)":"0","best":"0"},"status":"Null children give heights -1; leaf returns 0."}'::jsonb),
('diameter-binary-tree', 6, 'Leaf 5: h=0', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":4,"state":"visited"},{"id":"e","value":5,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"h(5)":"0","best":"0"},"status":"Return 0."}'::jsonb),
('diameter-binary-tree', 7, 'Node 2: L=1,R=1, dia=2', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"current"},{"id":"c","value":3,"state":"unvisited"},{"id":"d","value":4,"state":"visited"},{"id":"e","value":5,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"h(2)":"1","best":"2"},"status":"Path 4-2-5 has 2 edges. Update best."}'::jsonb),
('diameter-binary-tree', 8, 'Leaf 3: h=0', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"current"},{"id":"d","value":4,"state":"visited"},{"id":"e","value":5,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"h(3)":"0","best":"2"},"status":"Return 0."}'::jsonb),
('diameter-binary-tree', 9, 'Root 1: L=2,R=1, dia=3', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"current"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"},{"id":"d","value":4,"state":"visited"},{"id":"e","value":5,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"h(1)":"2","best":"3"},"status":"Path 4-2-1-3 or 5-2-1-3 has 3 edges."}'::jsonb),
('diameter-binary-tree', 10, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"},{"id":"d","value":4,"state":"visited"},{"id":"e","value":5,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"best":"3"},"status":"DFS done."}'::jsonb),
('diameter-binary-tree', 11, 'Result', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"},{"id":"d","value":4,"state":"visited"},{"id":"e","value":5,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"answer":"3"},"status":"Diameter = 3 edges."}'::jsonb),
('diameter-binary-tree', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"},{"id":"d","value":4,"state":"visited"},{"id":"e","value":5,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Post-order DFS, track best = L+R across all nodes."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('invert-binary-tree', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":7,"state":"unvisited"},{"id":"d","value":1,"state":"unvisited"},{"id":"e","value":3,"state":"unvisited"},{"id":"f","value":6,"state":"unvisited"},{"id":"g","value":9,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"c","child":"f","side":"left"},{"parent":"c","child":"g","side":"right"}],"hashmap":{"goal":"mirror the tree"},"status":"Mirror the tree: swap every node''s children."}'::jsonb),
('invert-binary-tree', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":7,"state":"unvisited"},{"id":"d","value":1,"state":"unvisited"},{"id":"e","value":3,"state":"unvisited"},{"id":"f","value":6,"state":"unvisited"},{"id":"g","value":9,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"c","child":"f","side":"left"},{"parent":"c","child":"g","side":"right"}],"hashmap":{"approach":"post-order DFS"},"status":"Recurse into left and right, then swap pointers at this node."}'::jsonb),
('invert-binary-tree', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":7,"state":"unvisited"},{"id":"d","value":1,"state":"unvisited"},{"id":"e","value":3,"state":"unvisited"},{"id":"f","value":6,"state":"unvisited"},{"id":"g","value":9,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"c","child":"f","side":"left"},{"parent":"c","child":"g","side":"right"}],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Every node visited once."}'::jsonb),
('invert-binary-tree', 4, 'Enter root (4)', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"current"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":7,"state":"unvisited"},{"id":"d","value":1,"state":"unvisited"},{"id":"e","value":3,"state":"unvisited"},{"id":"f","value":6,"state":"unvisited"},{"id":"g","value":9,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"c","child":"f","side":"left"},{"parent":"c","child":"g","side":"right"}],"hashmap":{"call":"invert(4)"},"status":"Recurse left then right, swap last."}'::jsonb),
('invert-binary-tree', 5, 'At node 2', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"unvisited"},{"id":"b","value":2,"state":"current"},{"id":"c","value":7,"state":"unvisited"},{"id":"d","value":1,"state":"unvisited"},{"id":"e","value":3,"state":"unvisited"},{"id":"f","value":6,"state":"unvisited"},{"id":"g","value":9,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"c","child":"f","side":"left"},{"parent":"c","child":"g","side":"right"}],"hashmap":{"call":"invert(2)"},"status":"Recurse into leaves 1 and 3."}'::jsonb),
('invert-binary-tree', 6, 'Swap children of 2 -> [3,1]', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"unvisited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":7,"state":"unvisited"},{"id":"d","value":1,"state":"visited"},{"id":"e","value":3,"state":"visited"},{"id":"f","value":6,"state":"unvisited"},{"id":"g","value":9,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"e","side":"left"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"f","side":"left"},{"parent":"c","child":"g","side":"right"}],"hashmap":{},"status":"Leaves return unchanged; swap assigns 3 left, 1 right."}'::jsonb),
('invert-binary-tree', 7, 'At node 7', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"unvisited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":7,"state":"current"},{"id":"d","value":1,"state":"visited"},{"id":"e","value":3,"state":"visited"},{"id":"f","value":6,"state":"unvisited"},{"id":"g","value":9,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"e","side":"left"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"f","side":"left"},{"parent":"c","child":"g","side":"right"}],"hashmap":{"call":"invert(7)"},"status":"Recurse into 6 and 9."}'::jsonb),
('invert-binary-tree', 8, 'Swap children of 7 -> [9,6]', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"unvisited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":7,"state":"visited"},{"id":"d","value":1,"state":"visited"},{"id":"e","value":3,"state":"visited"},{"id":"f","value":6,"state":"visited"},{"id":"g","value":9,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"e","side":"left"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"g","side":"left"},{"parent":"c","child":"f","side":"right"}],"hashmap":{},"status":"9 left, 6 right."}'::jsonb),
('invert-binary-tree', 9, 'Swap children of root 4', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":7,"state":"visited"},{"id":"d","value":1,"state":"visited"},{"id":"e","value":3,"state":"visited"},{"id":"f","value":6,"state":"visited"},{"id":"g","value":9,"state":"visited"}],"edges":[{"parent":"a","child":"c","side":"left"},{"parent":"a","child":"b","side":"right"},{"parent":"b","child":"e","side":"left"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"g","side":"left"},{"parent":"c","child":"f","side":"right"}],"hashmap":{},"status":"7 becomes left child, 2 becomes right child."}'::jsonb),
('invert-binary-tree', 10, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":7,"state":"visited"},{"id":"d","value":1,"state":"visited"},{"id":"e","value":3,"state":"visited"},{"id":"f","value":6,"state":"visited"},{"id":"g","value":9,"state":"visited"}],"edges":[{"parent":"a","child":"c","side":"left"},{"parent":"a","child":"b","side":"right"},{"parent":"b","child":"e","side":"left"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"g","side":"left"},{"parent":"c","child":"f","side":"right"}],"hashmap":{"status":"done"},"status":"All swaps finished."}'::jsonb),
('invert-binary-tree', 11, 'Result', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":7,"state":"visited"},{"id":"d","value":1,"state":"visited"},{"id":"e","value":3,"state":"visited"},{"id":"f","value":6,"state":"visited"},{"id":"g","value":9,"state":"visited"}],"edges":[{"parent":"a","child":"c","side":"left"},{"parent":"a","child":"b","side":"right"},{"parent":"b","child":"e","side":"left"},{"parent":"b","child":"d","side":"right"},{"parent":"c","child":"g","side":"left"},{"parent":"c","child":"f","side":"right"}],"hashmap":{"preorder":"4,7,9,6,2,3,1"},"status":"Tree mirrored."}'::jsonb),
('invert-binary-tree', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":4,"state":"visited"}],"edges":[],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Recursive swap inverts the tree."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('kth-smallest-bst', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"unvisited"},{"id":"b","value":3,"state":"unvisited"},{"id":"c","value":6,"state":"unvisited"},{"id":"d","value":2,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":1,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"d","child":"f","side":"left"}],"hashmap":{"k":"3","goal":"3rd smallest"},"status":"Find the 3rd smallest value in the BST."}'::jsonb),
('kth-smallest-bst', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"unvisited"},{"id":"b","value":3,"state":"unvisited"},{"id":"c","value":6,"state":"unvisited"},{"id":"d","value":2,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":1,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"d","child":"f","side":"left"}],"hashmap":{"approach":"iterative in-order"},"status":"In-order traversal on a BST visits keys in sorted order. Stop when count reaches k."}'::jsonb),
('kth-smallest-bst', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"unvisited"},{"id":"b","value":3,"state":"unvisited"},{"id":"c","value":6,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"time":"O(h+k)","space":"O(h)"},"status":"Descend to leftmost in O(h), then pop k nodes."}'::jsonb),
('kth-smallest-bst', 4, 'Push left spine: 5,3,2,1', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"highlighted"},{"id":"b","value":3,"state":"highlighted"},{"id":"c","value":6,"state":"unvisited"},{"id":"d","value":2,"state":"highlighted"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":1,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"d","child":"f","side":"left"}],"hashmap":{"stack":"[5,3,2,1]","count":"0"},"status":"Walk left, pushing each node."}'::jsonb),
('kth-smallest-bst', 5, 'Pop 1 (count=1)', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"highlighted"},{"id":"b","value":3,"state":"highlighted"},{"id":"c","value":6,"state":"unvisited"},{"id":"d","value":2,"state":"highlighted"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":1,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"d","child":"f","side":"left"}],"hashmap":{"stack":"[5,3,2]","count":"1","visit":"1"},"status":"Smallest is 1. Not k yet."}'::jsonb),
('kth-smallest-bst', 6, 'Pop 2 (count=2)', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"highlighted"},{"id":"b","value":3,"state":"highlighted"},{"id":"c","value":6,"state":"unvisited"},{"id":"d","value":2,"state":"visited"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":1,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"d","child":"f","side":"left"}],"hashmap":{"stack":"[5,3]","count":"2","visit":"2"},"status":"2''s right is null."}'::jsonb),
('kth-smallest-bst', 7, 'Pop 3 (count=3 = k)', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"highlighted"},{"id":"b","value":3,"state":"visited"},{"id":"c","value":6,"state":"unvisited"},{"id":"d","value":2,"state":"visited"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":1,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"d","child":"f","side":"left"}],"hashmap":{"stack":"[5]","count":"3","visit":"3"},"status":"count hit k — return 3."}'::jsonb),
('kth-smallest-bst', 8, 'Skip 4, 5, 6', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"unvisited"},{"id":"b","value":3,"state":"visited"},{"id":"c","value":6,"state":"unvisited"},{"id":"d","value":2,"state":"visited"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":1,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"d","child":"f","side":"left"}],"hashmap":{"note":"never visited"},"status":"Early stop saves unnecessary work on nodes with larger keys."}'::jsonb),
('kth-smallest-bst', 9, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"unvisited"},{"id":"b","value":3,"state":"visited"},{"id":"c","value":6,"state":"unvisited"},{"id":"d","value":2,"state":"visited"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":1,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"d","child":"f","side":"left"}],"hashmap":{"done":"true"},"status":"Exit loop."}'::jsonb),
('kth-smallest-bst', 10, 'Result', '{"type":"tree","nodes":[{"id":"b","value":3,"state":"visited"}],"edges":[],"hashmap":{"answer":"3"},"status":"3rd smallest is 3."}'::jsonb),
('kth-smallest-bst', 11, 'Return + Recap', '{"type":"tree","nodes":[{"id":"b","value":3,"state":"visited"}],"edges":[],"hashmap":{"time":"O(h+k)","space":"O(h)"},"status":"Iterative in-order with early termination."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('letter-combinations', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"digits":"\"23\"","2":"abc","3":"def"},"status":"Generate all letter combos by mapping phone digits to letters."}'::jsonb),
('letter-combinations', 2, 'Approach', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"approach":"DFS recursion tree"},"status":"For each digit, branch over its letters; depth = len(digits)."}'::jsonb),
('letter-combinations', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(3^n * n)","space":"O(n)"},"status":"Up to 3-4 letters per digit, n digits deep."}'::jsonb),
('letter-combinations', 4, 'Root: idx=0, path=\"\"', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"current"}],"edges":[],"hashmap":{"path":"\"\"","result":"[]"},"status":"Branch on letters of ''2''."}'::jsonb),
('letter-combinations', 5, 'Branch ''a'' -> path=\"a\"', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":97,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"}],"hashmap":{"path":"\"a\""},"status":"Child a — next digit is ''3''."}'::jsonb),
('letter-combinations', 6, 'a->d', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":97,"state":"visited"},{"id":"ad","value":100,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"ad","side":"left"}],"hashmap":{"result":"[ad]"},"status":"Leaf — emit \"ad\"."}'::jsonb),
('letter-combinations', 7, 'a->e, a->f', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":97,"state":"visited"},{"id":"ad","value":100,"state":"visited"},{"id":"ae","value":101,"state":"visited"},{"id":"af","value":102,"state":"visited"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"ad","side":"left"},{"parent":"a","child":"ae","side":"left"},{"parent":"a","child":"af","side":"right"}],"hashmap":{"result":"[ad,ae,af]"},"status":"Backtrack and try e, f under a."}'::jsonb),
('letter-combinations', 8, 'Branch ''b''', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"b","value":98,"state":"current"}],"edges":[{"parent":"r","child":"b","side":"right"}],"hashmap":{"path":"\"b\""},"status":"Explore b-subtree: bd, be, bf."}'::jsonb),
('letter-combinations', 9, 'bd, be, bf', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"b","value":98,"state":"visited"},{"id":"bd","value":100,"state":"visited"},{"id":"be","value":101,"state":"visited"},{"id":"bf","value":102,"state":"visited"}],"edges":[{"parent":"r","child":"b","side":"right"},{"parent":"b","child":"bd","side":"left"},{"parent":"b","child":"be","side":"left"},{"parent":"b","child":"bf","side":"right"}],"hashmap":{"result":"[ad,ae,af,bd,be,bf]"},"status":"All b-branch leaves emitted."}'::jsonb),
('letter-combinations', 10, 'Branch ''c''', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"c","value":99,"state":"visited"},{"id":"cd","value":100,"state":"visited"},{"id":"ce","value":101,"state":"visited"},{"id":"cf","value":102,"state":"visited"}],"edges":[{"parent":"r","child":"c","side":"right"},{"parent":"c","child":"cd","side":"left"},{"parent":"c","child":"ce","side":"left"},{"parent":"c","child":"cf","side":"right"}],"hashmap":{"result":"[...cd,ce,cf]"},"status":"Explore c-subtree: cd, ce, cf."}'::jsonb),
('letter-combinations', 11, 'Termination', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"result_size":"9"},"status":"All branches exhausted."}'::jsonb),
('letter-combinations', 12, 'Result', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"answer":"[ad,ae,af,bd,be,bf,cd,ce,cf]"},"status":"9 combinations."}'::jsonb),
('letter-combinations', 13, 'Return + Recap', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"time":"O(3^n * n)","space":"O(n)"},"status":"DFS recursion tree over the digit mapping."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('level-order-traversal', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"unvisited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"goal":"[[level0],[level1],...]"},"status":"Return nodes grouped by depth."}'::jsonb),
('level-order-traversal', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"unvisited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"approach":"BFS with level size snapshot"},"status":"Each iteration pops exactly the nodes of the current level."}'::jsonb),
('level-order-traversal', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(n)","space":"O(w)"},"status":"Every node enqueued once."}'::jsonb),
('level-order-traversal', 4, 'Init queue=[3]', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"current"},{"id":"b","value":9,"state":"unvisited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[3]","result":"[]"},"status":"Begin BFS."}'::jsonb),
('level-order-traversal', 5, 'Level 0: pop 3, push children', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"highlighted"},{"id":"c","value":20,"state":"highlighted"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[9,20]","result":"[[3]]"},"status":"Snapshot size=1. Record level 0 = [3]."}'::jsonb),
('level-order-traversal', 6, 'Pop 9 (no children)', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"current"},{"id":"c","value":20,"state":"highlighted"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[20]","level":"[9]"},"status":"9 has no children to enqueue."}'::jsonb),
('level-order-traversal', 7, 'Pop 20, push 15,7', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"current"},{"id":"d","value":15,"state":"highlighted"},{"id":"e","value":7,"state":"highlighted"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[15,7]","result":"[[3],[9,20]]"},"status":"Level 1 complete."}'::jsonb),
('level-order-traversal', 8, 'Level 2 size=2, pop 15', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"current"},{"id":"e","value":7,"state":"highlighted"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[7]","level":"[15]"},"status":"Leaf — nothing to enqueue."}'::jsonb),
('level-order-traversal', 9, 'Pop 7', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[]","result":"[[3],[9,20],[15,7]]"},"status":"Level 2 done."}'::jsonb),
('level-order-traversal', 10, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"queue":"[]"},"status":"Queue empty."}'::jsonb),
('level-order-traversal', 11, 'Result', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"}],"edges":[],"hashmap":{"answer":"[[3],[9,20],[15,7]]"},"status":"3 levels."}'::jsonb),
('level-order-traversal', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"}],"edges":[],"hashmap":{"time":"O(n)","space":"O(w)"},"status":"BFS with size snapshot per level."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('longest-word-dictionary', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"words":"[w,wo,wor,worl,world]"},"status":"Find the longest word buildable one character at a time from existing words."}'::jsonb),
('longest-word-dictionary', 2, 'Approach', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"approach":"trie + DFS"},"status":"Insert all words. DFS only through nodes where isEnd==true; pick longest path."}'::jsonb),
('longest-word-dictionary', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(sum|w|)","space":"O(sum|w|)"},"status":"Trie build and DFS are both linear."}'::jsonb),
('longest-word-dictionary', 4, 'Build trie: insert w', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"w","value":119,"state":"current"}],"edges":[{"parent":"r","child":"w","side":"left"}],"hashmap":{"end":"{w}"},"status":"Insert single char ''w''. Mark end."}'::jsonb),
('longest-word-dictionary', 5, 'Insert wo', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"w","value":119,"state":"visited"},{"id":"o","value":111,"state":"current"}],"edges":[{"parent":"r","child":"w","side":"left"},{"parent":"w","child":"o","side":"left"}],"hashmap":{"end":"{w,wo}"},"status":"''wo'' extends ''w''."}'::jsonb),
('longest-word-dictionary', 6, 'Insert wor, worl, world', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"w","value":119,"state":"visited"},{"id":"o","value":111,"state":"visited"},{"id":"rr","value":114,"state":"visited"},{"id":"l","value":108,"state":"visited"},{"id":"dd","value":100,"state":"current"}],"edges":[{"parent":"r","child":"w","side":"left"},{"parent":"w","child":"o","side":"left"},{"parent":"o","child":"rr","side":"left"},{"parent":"rr","child":"l","side":"left"},{"parent":"l","child":"dd","side":"left"}],"hashmap":{"end":"{w,wo,wor,worl,world}"},"status":"Every prefix is itself a dictionary word."}'::jsonb),
('longest-word-dictionary', 7, 'DFS from root, only through end-nodes', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"current"},{"id":"w","value":119,"state":"visited"},{"id":"o","value":111,"state":"visited"},{"id":"rr","value":114,"state":"visited"},{"id":"l","value":108,"state":"visited"},{"id":"dd","value":100,"state":"visited"}],"edges":[{"parent":"r","child":"w","side":"left"},{"parent":"w","child":"o","side":"left"},{"parent":"o","child":"rr","side":"left"},{"parent":"rr","child":"l","side":"left"},{"parent":"l","child":"dd","side":"left"}],"hashmap":{"best":"\"\""},"status":"Root is virtual; start DFS."}'::jsonb),
('longest-word-dictionary', 8, 'Descend w (end) -> wo (end)', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"w","value":119,"state":"current"},{"id":"o","value":111,"state":"current"},{"id":"rr","value":114,"state":"visited"},{"id":"l","value":108,"state":"visited"},{"id":"dd","value":100,"state":"visited"}],"edges":[{"parent":"r","child":"w","side":"left"},{"parent":"w","child":"o","side":"left"},{"parent":"o","child":"rr","side":"left"},{"parent":"rr","child":"l","side":"left"},{"parent":"l","child":"dd","side":"left"}],"hashmap":{"best":"wo"},"status":"Every intermediate node is an end — update best."}'::jsonb),
('longest-word-dictionary', 9, 'wor (end) -> worl (end)', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"w","value":119,"state":"visited"},{"id":"o","value":111,"state":"visited"},{"id":"rr","value":114,"state":"current"},{"id":"l","value":108,"state":"current"},{"id":"dd","value":100,"state":"visited"}],"edges":[{"parent":"r","child":"w","side":"left"},{"parent":"w","child":"o","side":"left"},{"parent":"o","child":"rr","side":"left"},{"parent":"rr","child":"l","side":"left"},{"parent":"l","child":"dd","side":"left"}],"hashmap":{"best":"worl"},"status":"Still allowed — both are ends."}'::jsonb),
('longest-word-dictionary', 10, 'world (end)', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"w","value":119,"state":"visited"},{"id":"o","value":111,"state":"visited"},{"id":"rr","value":114,"state":"visited"},{"id":"l","value":108,"state":"visited"},{"id":"dd","value":100,"state":"current"}],"edges":[{"parent":"r","child":"w","side":"left"},{"parent":"w","child":"o","side":"left"},{"parent":"o","child":"rr","side":"left"},{"parent":"rr","child":"l","side":"left"},{"parent":"l","child":"dd","side":"left"}],"hashmap":{"best":"world"},"status":"Deepest valid word found."}'::jsonb),
('longest-word-dictionary', 11, 'Termination', '{"type":"tree","nodes":[{"id":"dd","value":100,"state":"visited"}],"edges":[],"hashmap":{"done":"true"},"status":"No children to extend."}'::jsonb),
('longest-word-dictionary', 12, 'Result', '{"type":"tree","nodes":[{"id":"dd","value":100,"state":"visited"}],"edges":[],"hashmap":{"answer":"\"world\""},"status":"Tie-break by lexicographic order if needed."}'::jsonb),
('longest-word-dictionary', 13, 'Return + Recap', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"time":"O(N)","space":"O(N)"},"status":"Trie + guided DFS."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('lowest-common-ancestor', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":8,"state":"unvisited"},{"id":"d","value":0,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":7,"state":"unvisited"},{"id":"g","value":9,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"c","child":"f","side":"left"},{"parent":"c","child":"g","side":"right"}],"hashmap":{"p":"2","q":"8"},"status":"Find lowest node whose subtree contains both p and q."}'::jsonb),
('lowest-common-ancestor', 2, 'Approach (BST)', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":8,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"rule":"split-point of p and q is LCA"},"status":"Descend: go right if both > node, left if both < node, else node is LCA."}'::jsonb),
('lowest-common-ancestor', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(h)","space":"O(1)"},"status":"Single root-to-split path."}'::jsonb),
('lowest-common-ancestor', 4, 'At root 6', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"current"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":8,"state":"unvisited"},{"id":"d","value":0,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"},{"id":"f","value":7,"state":"unvisited"},{"id":"g","value":9,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"},{"parent":"c","child":"f","side":"left"},{"parent":"c","child":"g","side":"right"}],"hashmap":{"check":"2<6<8"},"status":"p on left, q on right — 6 is the split point."}'::jsonb),
('lowest-common-ancestor', 5, 'Detected split: return 6', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"visited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":8,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"lca":"6"},"status":"No further descent needed."}'::jsonb),
('lowest-common-ancestor', 6, 'Illustrate alt case p=0 q=4', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"current"},{"id":"b","value":2,"state":"unvisited"},{"id":"d","value":0,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"both<6":"true"},"status":"Both < 6 — descend left to 2."}'::jsonb),
('lowest-common-ancestor', 7, 'At 2 (would-be split)', '{"type":"tree","nodes":[{"id":"b","value":2,"state":"current"},{"id":"d","value":0,"state":"unvisited"},{"id":"e","value":4,"state":"unvisited"}],"edges":[{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"0<2<4":"true"},"status":"2 would be the LCA for p=0, q=4."}'::jsonb),
('lowest-common-ancestor', 8, 'Back to original p=2, q=8', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"visited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":8,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"lca":"6"},"status":"Answer for original query."}'::jsonb),
('lowest-common-ancestor', 9, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"visited"}],"edges":[],"hashmap":{"done":"true"},"status":"Loop ended at split."}'::jsonb),
('lowest-common-ancestor', 10, 'Result', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"visited"}],"edges":[],"hashmap":{"answer":"6"},"status":"LCA(2,8)=6."}'::jsonb),
('lowest-common-ancestor', 11, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":6,"state":"visited"}],"edges":[],"hashmap":{"time":"O(h)","space":"O(1)"},"status":"BST split-point is LCA — no recursion needed."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('max-depth-binary-tree', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"unvisited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"goal":"count longest root-to-leaf in nodes"},"status":"Max depth = number of nodes on the longest path from root to leaf."}'::jsonb),
('max-depth-binary-tree', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"}],"edges":[],"hashmap":{"formula":"depth(n) = 1 + max(depth(left),depth(right))"},"status":"Recursive DFS. Leaves return 1; null returns 0."}'::jsonb),
('max-depth-binary-tree', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Each node visited once."}'::jsonb),
('max-depth-binary-tree', 4, 'Enter root(3)', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"current"},{"id":"b","value":9,"state":"unvisited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"call":"depth(3)"},"status":"Recurse left then right."}'::jsonb),
('max-depth-binary-tree', 5, 'depth(9)=1', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"current"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"depth(9)":"1"},"status":"Leaf."}'::jsonb),
('max-depth-binary-tree', 6, 'Enter 20', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"current"},{"id":"d","value":15,"state":"unvisited"},{"id":"e","value":7,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"call":"depth(20)"},"status":"Recurse into 15 and 7."}'::jsonb),
('max-depth-binary-tree', 7, 'depth(15)=1, depth(7)=1', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"unvisited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{},"status":"Both leaves return 1."}'::jsonb),
('max-depth-binary-tree', 8, 'depth(20)=2', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"depth(20)":"2"},"status":"1+max(1,1)=2."}'::jsonb),
('max-depth-binary-tree', 9, 'depth(3)=3', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":9,"state":"visited"},{"id":"c","value":20,"state":"visited"},{"id":"d","value":15,"state":"visited"},{"id":"e","value":7,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"depth(3)":"3"},"status":"1+max(1,2)=3."}'::jsonb),
('max-depth-binary-tree', 10, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"}],"edges":[],"hashmap":{"done":"true"},"status":"Recursion unwound."}'::jsonb),
('max-depth-binary-tree', 11, 'Result', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"}],"edges":[],"hashmap":{"answer":"3"},"status":"Max depth is 3."}'::jsonb),
('max-depth-binary-tree', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"}],"edges":[],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"One DFS pass."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('palindrome-partitioning', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"s":"\"aab\""},"status":"Partition s into substrings where each piece is a palindrome."}'::jsonb),
('palindrome-partitioning', 2, 'Approach', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"approach":"DFS backtracking"},"status":"At each index, try every cut; if the prefix is a palindrome, recurse on the remainder."}'::jsonb),
('palindrome-partitioning', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(n*2^n)","space":"O(n)"},"status":"Exponential partitions, linear palindrome check."}'::jsonb),
('palindrome-partitioning', 4, 'Root idx=0', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"current"}],"edges":[],"hashmap":{"path":"[]"},"status":"Try cuts ending at 1, 2, 3."}'::jsonb),
('palindrome-partitioning', 5, 'Cut \"a\" (palindrome)', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":97,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"}],"hashmap":{"path":"[a]","remain":"ab"},"status":"Descend with prefix \"a\"."}'::jsonb),
('palindrome-partitioning', 6, 'Cut \"a\" again', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":97,"state":"visited"},{"id":"aa","value":97,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"aa","side":"left"}],"hashmap":{"path":"[a,a]","remain":"b"},"status":"Second \"a\" is a palindrome too."}'::jsonb),
('palindrome-partitioning', 7, 'Cut \"b\" -> record [a,a,b]', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":97,"state":"visited"},{"id":"aa","value":97,"state":"visited"},{"id":"b1","value":98,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"aa","side":"left"},{"parent":"aa","child":"b1","side":"left"}],"hashmap":{"result":"[[a,a,b]]"},"status":"Empty remainder — emit."}'::jsonb),
('palindrome-partitioning', 8, 'Backtrack: try \"ab\" at idx=1 — not palindrome', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"a","value":97,"state":"visited"},{"id":"ab","value":0,"state":"current"}],"edges":[{"parent":"r","child":"a","side":"left"},{"parent":"a","child":"ab","side":"right"}],"hashmap":{"prune":"true"},"status":"\"ab\" not a palindrome — prune."}'::jsonb),
('palindrome-partitioning', 9, 'At root try \"aa\" (palindrome)', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"current"},{"id":"aa2","value":97,"state":"current"}],"edges":[{"parent":"r","child":"aa2","side":"right"}],"hashmap":{"path":"[aa]","remain":"b"},"status":"Prefix \"aa\" is a palindrome."}'::jsonb),
('palindrome-partitioning', 10, 'Cut \"b\" -> record [aa,b]', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"aa2","value":97,"state":"visited"},{"id":"b2","value":98,"state":"current"}],"edges":[{"parent":"r","child":"aa2","side":"right"},{"parent":"aa2","child":"b2","side":"left"}],"hashmap":{"result":"[[a,a,b],[aa,b]]"},"status":"Second partition recorded."}'::jsonb),
('palindrome-partitioning', 11, 'Try \"aab\" — not palindrome', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"aab","value":0,"state":"current"}],"edges":[{"parent":"r","child":"aab","side":"right"}],"hashmap":{"prune":"true"},"status":"\"aab\" reversed is \"baa\" — not a palindrome."}'::jsonb),
('palindrome-partitioning', 12, 'Result', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"answer":"[[a,a,b],[aa,b]]"},"status":"Two valid palindrome partitions."}'::jsonb),
('palindrome-partitioning', 13, 'Return + Recap', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"time":"O(n*2^n)","space":"O(n)"},"status":"DFS cuts + palindrome check."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('replace-words', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"dict":"[cat,bat,rat]","sentence":"the cattle was rattled by the battery"},"status":"Replace each word by its shortest root from dict."}'::jsonb),
('replace-words', 2, 'Approach', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"approach":"trie of roots"},"status":"Build a trie of roots. For each word, walk the trie until hitting an end-node."}'::jsonb),
('replace-words', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(T)","space":"O(R)"},"status":"T = total chars in sentence; R = total chars in roots."}'::jsonb),
('replace-words', 4, 'Build trie: insert cat, bat, rat', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"c","value":99,"state":"visited"},{"id":"a1","value":97,"state":"visited"},{"id":"t1","value":116,"state":"visited"},{"id":"b","value":98,"state":"visited"},{"id":"a2","value":97,"state":"visited"},{"id":"t2","value":116,"state":"visited"},{"id":"rr","value":114,"state":"visited"},{"id":"a3","value":97,"state":"visited"},{"id":"t3","value":116,"state":"current"}],"edges":[{"parent":"r","child":"c","side":"left"},{"parent":"c","child":"a1","side":"left"},{"parent":"a1","child":"t1","side":"left"},{"parent":"r","child":"b","side":"left"},{"parent":"b","child":"a2","side":"left"},{"parent":"a2","child":"t2","side":"left"},{"parent":"r","child":"rr","side":"right"},{"parent":"rr","child":"a3","side":"left"},{"parent":"a3","child":"t3","side":"left"}],"hashmap":{"ends":"{cat,bat,rat}"},"status":"3 separate branches, each 3 chars deep."}'::jsonb),
('replace-words', 5, 'Scan \"the\": no ''t'' root prefix end', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"current"}],"edges":[],"hashmap":{"no_match":"the"},"status":"''t'' not a trie root. Keep as-is."}'::jsonb),
('replace-words', 6, 'Scan \"cattle\" -> walk c,a,t hits end', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"c","value":99,"state":"visited"},{"id":"a1","value":97,"state":"visited"},{"id":"t1","value":116,"state":"current"}],"edges":[{"parent":"r","child":"c","side":"left"},{"parent":"c","child":"a1","side":"left"},{"parent":"a1","child":"t1","side":"left"}],"hashmap":{"root":"cat"},"status":"Replace \"cattle\" -> \"cat\"."}'::jsonb),
('replace-words', 7, 'Scan \"was\" -> no root', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"current"}],"edges":[],"hashmap":{"no_match":"was"},"status":"Keep \"was\"."}'::jsonb),
('replace-words', 8, 'Scan \"rattled\" -> r,a,t end', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"rr","value":114,"state":"visited"},{"id":"a3","value":97,"state":"visited"},{"id":"t3","value":116,"state":"current"}],"edges":[{"parent":"r","child":"rr","side":"right"},{"parent":"rr","child":"a3","side":"left"},{"parent":"a3","child":"t3","side":"left"}],"hashmap":{"root":"rat"},"status":"Replace with \"rat\"."}'::jsonb),
('replace-words', 9, 'Scan \"by\" -> no root', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"current"}],"edges":[],"hashmap":{"no_match":"by"},"status":"Keep \"by\"."}'::jsonb),
('replace-words', 10, 'Scan \"battery\" -> b,a,t end', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"b","value":98,"state":"visited"},{"id":"a2","value":97,"state":"visited"},{"id":"t2","value":116,"state":"current"}],"edges":[{"parent":"r","child":"b","side":"left"},{"parent":"b","child":"a2","side":"left"},{"parent":"a2","child":"t2","side":"left"}],"hashmap":{"root":"bat"},"status":"Replace with \"bat\"."}'::jsonb),
('replace-words', 11, 'Termination', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"done":"true"},"status":"All words processed."}'::jsonb),
('replace-words', 12, 'Result', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"answer":"the cat was rat by the bat"},"status":"Sentence rewritten with shortest roots."}'::jsonb),
('replace-words', 13, 'Return + Recap', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"time":"O(T)","space":"O(R)"},"status":"Trie of roots + linear scan."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('same-tree', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"p":"[1,2,3]","q":"[1,2,3]"},"status":"Return true if trees p and q have identical structure and values."}'::jsonb),
('same-tree', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"}],"edges":[],"hashmap":{"approach":"parallel DFS"},"status":"Recurse on (p.left,q.left) and (p.right,q.right). Fail early on any mismatch."}'::jsonb),
('same-tree', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Visit each matching pair once."}'::jsonb),
('same-tree', 4, 'Compare roots', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"current"},{"id":"b","value":2,"state":"unvisited"},{"id":"c","value":3,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"p.val":"1","q.val":"1"},"status":"Values match — recurse."}'::jsonb),
('same-tree', 5, 'Compare left children (2,2)', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"current"},{"id":"c","value":3,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"match":"2==2"},"status":"Leaf pair matches."}'::jsonb),
('same-tree', 6, 'Left leaves null pair returns true', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"null==null":"true"},"status":"Both null children on deeper recursion."}'::jsonb),
('same-tree', 7, 'Compare right children (3,3)', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"match":"3==3"},"status":"Leaf pair matches."}'::jsonb),
('same-tree', 8, 'Children of 3 are null/null', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"null==null":"true"},"status":"No further divergence."}'::jsonb),
('same-tree', 9, 'All comparisons true', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"},{"id":"b","value":2,"state":"visited"},{"id":"c","value":3,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"}],"hashmap":{"combine":"true&&true"},"status":"All recursive calls returned true."}'::jsonb),
('same-tree', 10, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"}],"edges":[],"hashmap":{"done":"true"},"status":"Root call returns."}'::jsonb),
('same-tree', 11, 'Result', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"}],"edges":[],"hashmap":{"answer":"true"},"status":"Trees identical."}'::jsonb),
('same-tree', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":1,"state":"visited"}],"edges":[],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Parallel DFS with early exit."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('search-suggestions-system', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"products":"[mobile,moneypot,monitor]","q":"mou"},"status":"For each prefix of searchWord return up to 3 matching products (lexicographic)."}'::jsonb),
('search-suggestions-system', 2, 'Approach', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"approach":"trie with sorted top-3"},"status":"Sort products, insert into trie, each node keeps first 3 products passing through."}'::jsonb),
('search-suggestions-system', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(sum|p|)","space":"O(sum|p|)"},"status":"Linear build; O(|q|) lookup."}'::jsonb),
('search-suggestions-system', 4, 'Sort products', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"unvisited"}],"edges":[],"hashmap":{"sorted":"[mobile,moneypot,monitor]"},"status":"Already sorted lexicographically."}'::jsonb),
('search-suggestions-system', 5, 'Insert all into trie under m-o', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"m","value":109,"state":"visited"},{"id":"o","value":111,"state":"current"}],"edges":[{"parent":"r","child":"m","side":"left"},{"parent":"m","child":"o","side":"left"}],"hashmap":{"m.top3":"[mobile,moneypot,monitor]","o.top3":"[mobile,moneypot,monitor]"},"status":"All three share prefix \"mo\"."}'::jsonb),
('search-suggestions-system', 6, 'Branch at o: b, n', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"m","value":109,"state":"visited"},{"id":"o","value":111,"state":"visited"},{"id":"b","value":98,"state":"current"},{"id":"n","value":110,"state":"current"}],"edges":[{"parent":"r","child":"m","side":"left"},{"parent":"m","child":"o","side":"left"},{"parent":"o","child":"b","side":"left"},{"parent":"o","child":"n","side":"right"}],"hashmap":{"ob.top3":"[mobile]","on.top3":"[moneypot,monitor]"},"status":"After ''o'' the products split into b-branch and n-branch."}'::jsonb),
('search-suggestions-system', 7, 'Query \"m\" -> top3 at node m', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"m","value":109,"state":"current"}],"edges":[{"parent":"r","child":"m","side":"left"}],"hashmap":{"sugg[m]":"[mobile,moneypot,monitor]"},"status":"All 3 qualify."}'::jsonb),
('search-suggestions-system', 8, 'Query \"mo\" -> top3 at node o', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"m","value":109,"state":"visited"},{"id":"o","value":111,"state":"current"}],"edges":[{"parent":"r","child":"m","side":"left"},{"parent":"m","child":"o","side":"left"}],"hashmap":{"sugg[mo]":"[mobile,moneypot,monitor]"},"status":"Same 3 products."}'::jsonb),
('search-suggestions-system', 9, 'Query \"mou\" -> no u child', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"},{"id":"m","value":109,"state":"visited"},{"id":"o","value":111,"state":"visited"}],"edges":[{"parent":"r","child":"m","side":"left"},{"parent":"m","child":"o","side":"left"}],"hashmap":{"sugg[mou]":"[]"},"status":"No ''u'' branch under ''o'' — empty suggestions; stay empty for remaining queries."}'::jsonb),
('search-suggestions-system', 10, 'Termination', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"done":"true"},"status":"All prefixes processed."}'::jsonb),
('search-suggestions-system', 11, 'Result', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"answer":"[[mobile,moneypot,monitor],[mobile,moneypot,monitor],[]]"},"status":"3 lists for prefixes m, mo, mou."}'::jsonb),
('search-suggestions-system', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"r","value":0,"state":"visited"}],"edges":[],"hashmap":{"time":"O(N)","space":"O(N)"},"status":"Trie nodes cache top-3 sorted matches."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('subtree-of-another', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"},{"id":"b","value":4,"state":"unvisited"},{"id":"c","value":5,"state":"unvisited"},{"id":"d","value":1,"state":"unvisited"},{"id":"e","value":2,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"target":"[4,1,2]"},"status":"Does any subtree of root exactly match subRoot?"}'::jsonb),
('subtree-of-another', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"}],"edges":[],"hashmap":{"approach":"DFS + sameTree"},"status":"At each node, test sameTree(node, subRoot). If not, recurse into children."}'::jsonb),
('subtree-of-another', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(n*m)","space":"O(h)"},"status":"Every node compared against subRoot in worst case."}'::jsonb),
('subtree-of-another', 4, 'At root 3: 3 != 4, recurse', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"current"},{"id":"b","value":4,"state":"unvisited"},{"id":"c","value":5,"state":"unvisited"},{"id":"d","value":1,"state":"unvisited"},{"id":"e","value":2,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"sameTree":"false"},"status":"Root values differ. Try left and right children."}'::jsonb),
('subtree-of-another', 5, 'Try at node 4: roots match', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":4,"state":"current"},{"id":"c","value":5,"state":"unvisited"},{"id":"d","value":1,"state":"unvisited"},{"id":"e","value":2,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"check":"sameTree(4,4)"},"status":"Compare children recursively."}'::jsonb),
('subtree-of-another', 6, 'Compare 1 vs 1 (left)', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":4,"state":"current"},{"id":"d","value":1,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"b","child":"d","side":"left"}],"hashmap":{"match":"true"},"status":"Leaves match."}'::jsonb),
('subtree-of-another', 7, 'Compare 2 vs 2 (right)', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":4,"state":"current"},{"id":"d","value":1,"state":"visited"},{"id":"e","value":2,"state":"current"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"match":"true"},"status":"Leaves match."}'::jsonb),
('subtree-of-another', 8, 'sameTree(4,4)=true', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":4,"state":"visited"},{"id":"d","value":1,"state":"visited"},{"id":"e","value":2,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"b","child":"d","side":"left"},{"parent":"b","child":"e","side":"right"}],"hashmap":{"found":"true"},"status":"Match! No need to check right subtree."}'::jsonb),
('subtree-of-another', 9, 'Short-circuit to true', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"},{"id":"b","value":4,"state":"visited"}],"edges":[{"parent":"a","child":"b","side":"left"}],"hashmap":{"recursion":"bubble up"},"status":"OR short-circuits back to the outer call."}'::jsonb),
('subtree-of-another', 10, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"}],"edges":[],"hashmap":{"done":"true"},"status":"Search completed."}'::jsonb),
('subtree-of-another', 11, 'Result', '{"type":"tree","nodes":[{"id":"b","value":4,"state":"visited"}],"edges":[],"hashmap":{"answer":"true"},"status":"Subtree rooted at 4 matches."}'::jsonb),
('subtree-of-another', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":3,"state":"visited"}],"edges":[],"hashmap":{"time":"O(n*m)","space":"O(h)"},"status":"DFS + sameTree equivalence."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('validate-bst', 1, 'Problem Setup', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"unvisited"},{"id":"b","value":1,"state":"unvisited"},{"id":"c","value":4,"state":"unvisited"},{"id":"d","value":3,"state":"unvisited"},{"id":"e","value":6,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"rule":"L<node<R recursively"},"status":"Check BST: every node''s value must lie in (lo, hi)."}'::jsonb),
('validate-bst', 2, 'Approach', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"unvisited"}],"edges":[],"hashmap":{"approach":"DFS with (lo,hi) bounds"},"status":"Descend left tightens hi to node.val; descend right tightens lo to node.val."}'::jsonb),
('validate-bst', 3, 'Complexity', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"unvisited"}],"edges":[],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"Visit each node once with constant work."}'::jsonb),
('validate-bst', 4, 'Root 5 in (-inf,+inf)', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"current"},{"id":"b","value":1,"state":"unvisited"},{"id":"c","value":4,"state":"unvisited"},{"id":"d","value":3,"state":"unvisited"},{"id":"e","value":6,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"bounds":"(-inf,+inf)"},"status":"OK — recurse left with hi=5, right with lo=5."}'::jsonb),
('validate-bst', 5, 'Left 1 in (-inf,5) OK', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"visited"},{"id":"b","value":1,"state":"current"},{"id":"c","value":4,"state":"unvisited"},{"id":"d","value":3,"state":"unvisited"},{"id":"e","value":6,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"bounds":"(-inf,5)"},"status":"1 < 5 — valid. Leaf."}'::jsonb),
('validate-bst', 6, 'Right 4 in (5,+inf)?', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"visited"},{"id":"b","value":1,"state":"visited"},{"id":"c","value":4,"state":"current"},{"id":"d","value":3,"state":"unvisited"},{"id":"e","value":6,"state":"unvisited"}],"edges":[{"parent":"a","child":"b","side":"left"},{"parent":"a","child":"c","side":"right"},{"parent":"c","child":"d","side":"left"},{"parent":"c","child":"e","side":"right"}],"hashmap":{"bounds":"(5,+inf)","val":"4"},"status":"4 is NOT > 5 — violation!"}'::jsonb),
('validate-bst', 7, 'Short-circuit return false', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"visited"},{"id":"c","value":4,"state":"visited"}],"edges":[{"parent":"a","child":"c","side":"right"}],"hashmap":{"fail":"true"},"status":"No need to examine 3 or 6."}'::jsonb),
('validate-bst', 8, 'Skipped 3 and 6', '{"type":"tree","nodes":[{"id":"d","value":3,"state":"unvisited"},{"id":"e","value":6,"state":"unvisited"}],"edges":[],"hashmap":{"skipped":"true"},"status":"Although 3 and 6 look locally ordered around 4, ancestor constraint already failed."}'::jsonb),
('validate-bst', 9, 'Why global bounds matter', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"visited"},{"id":"c","value":4,"state":"visited"}],"edges":[{"parent":"a","child":"c","side":"right"}],"hashmap":{"note":"right subtree of 5 must all be > 5"},"status":"Local parent-child checks are not enough; bounds propagate from every ancestor."}'::jsonb),
('validate-bst', 10, 'Termination', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"visited"}],"edges":[],"hashmap":{"done":"true"},"status":"Early exit."}'::jsonb),
('validate-bst', 11, 'Result', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"visited"}],"edges":[],"hashmap":{"answer":"false"},"status":"Not a valid BST."}'::jsonb),
('validate-bst', 12, 'Return + Recap', '{"type":"tree","nodes":[{"id":"a","value":5,"state":"visited"}],"edges":[],"hashmap":{"time":"O(n)","space":"O(h)"},"status":"DFS with min/max bounds is the canonical approach."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('linked-list-cycle', 1, 'Problem Setup', '{"type":"linked-list","nodes":[{"value":3,"state":"default"},{"value":2,"state":"default"},{"value":0,"state":"default"},{"value":-4,"state":"default"}],"pointers":{"head":0},"hashmap":{"cycle_at":"index 1"},"status":"Detect a cycle: some node''s next points back to an earlier node."}'::jsonb),
('linked-list-cycle', 2, 'Approach', '{"type":"linked-list","nodes":[{"value":3,"state":"default"},{"value":2,"state":"default"},{"value":0,"state":"default"},{"value":-4,"state":"default"}],"pointers":{},"hashmap":{"approach":"Floyd''s tortoise and hare"},"status":"Two pointers: slow advances 1, fast advances 2. They meet iff cycle."}'::jsonb),
('linked-list-cycle', 3, 'Complexity', '{"type":"linked-list","nodes":[{"value":3,"state":"default"},{"value":2,"state":"default"},{"value":0,"state":"default"},{"value":-4,"state":"default"}],"pointers":{},"hashmap":{"time":"O(n)","space":"O(1)"},"status":"Linear time, constant extra space."}'::jsonb),
('linked-list-cycle', 4, 'Init slow=fast=head', '{"type":"linked-list","nodes":[{"value":3,"state":"current"},{"value":2,"state":"default"},{"value":0,"state":"default"},{"value":-4,"state":"default"}],"pointers":{"slow":0,"fast":0},"hashmap":{},"status":"Both at index 0."}'::jsonb),
('linked-list-cycle', 5, 'Step: slow->1, fast->2', '{"type":"linked-list","nodes":[{"value":3,"state":"visited"},{"value":2,"state":"current"},{"value":0,"state":"highlighted"},{"value":-4,"state":"default"}],"pointers":{"slow":1,"fast":2},"hashmap":{},"status":"Different positions — keep moving."}'::jsonb),
('linked-list-cycle', 6, 'Step: slow->2, fast-> (wraps)', '{"type":"linked-list","nodes":[{"value":3,"state":"visited"},{"value":2,"state":"highlighted"},{"value":0,"state":"current"},{"value":-4,"state":"default"}],"pointers":{"slow":2,"fast":1},"hashmap":{"note":"fast: -4 -> 2"},"status":"Fast moves -4 then follows cycle back to node at index 1."}'::jsonb),
('linked-list-cycle', 7, 'Step: slow->3 (=-4), fast->3', '{"type":"linked-list","nodes":[{"value":3,"state":"visited"},{"value":2,"state":"visited"},{"value":0,"state":"visited"},{"value":-4,"state":"current"}],"pointers":{"slow":3,"fast":3},"hashmap":{"meet":"true"},"status":"They coincide at the -4 node."}'::jsonb),
('linked-list-cycle', 8, 'Meeting implies cycle', '{"type":"linked-list","nodes":[{"value":3,"state":"visited"},{"value":2,"state":"visited"},{"value":0,"state":"visited"},{"value":-4,"state":"visited"}],"pointers":{"slow":3,"fast":3},"hashmap":{"explanation":"in a non-cyclic list fast would reach null"},"status":"Any meeting before null proves a cycle exists."}'::jsonb),
('linked-list-cycle', 9, 'Termination', '{"type":"linked-list","nodes":[{"value":3,"state":"visited"},{"value":2,"state":"visited"},{"value":0,"state":"visited"},{"value":-4,"state":"visited"}],"pointers":{},"hashmap":{"done":"true"},"status":"Exit loop on slow==fast."}'::jsonb),
('linked-list-cycle', 10, 'Result', '{"type":"linked-list","nodes":[{"value":3,"state":"visited"},{"value":2,"state":"visited"},{"value":0,"state":"visited"},{"value":-4,"state":"visited"}],"pointers":{},"hashmap":{"answer":"true"},"status":"Cycle confirmed."}'::jsonb),
('linked-list-cycle', 11, 'Return + Recap', '{"type":"linked-list","nodes":[{"value":3,"state":"visited"},{"value":2,"state":"visited"},{"value":0,"state":"visited"},{"value":-4,"state":"visited"}],"pointers":{},"hashmap":{"time":"O(n)","space":"O(1)"},"status":"Floyd''s algorithm detects cycles in constant memory."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('merge-two-sorted', 1, 'Problem Setup', '{"type":"linked-list","nodes":[{"value":1,"state":"default"},{"value":2,"state":"default"},{"value":4,"state":"default"}],"pointers":{"l1":0},"hashmap":{"l2":"[1,3,4]"},"status":"Merge two sorted lists into one sorted list."}'::jsonb),
('merge-two-sorted', 2, 'Approach', '{"type":"linked-list","nodes":[{"value":1,"state":"default"},{"value":2,"state":"default"},{"value":4,"state":"default"}],"pointers":{},"hashmap":{"approach":"dummy + tail pointer"},"status":"Walk both lists; at each step append the smaller head."}'::jsonb),
('merge-two-sorted', 3, 'Complexity', '{"type":"linked-list","nodes":[{"value":1,"state":"default"}],"pointers":{},"hashmap":{"time":"O(n+m)","space":"O(1)"},"status":"Single pass; rewire in place."}'::jsonb),
('merge-two-sorted', 4, 'Init dummy, tail=dummy', '{"type":"linked-list","nodes":[{"value":1,"state":"current"},{"value":2,"state":"default"},{"value":4,"state":"default"}],"pointers":{"l1":0},"hashmap":{"l2_idx":"0","tail":"dummy"},"status":"Compare l1[0]=1 vs l2[0]=1 — tie, take l1."}'::jsonb),
('merge-two-sorted', 5, 'Append 1 from l1', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"current"},{"value":4,"state":"default"}],"pointers":{"l1":1},"hashmap":{"result":"1","l2_idx":"0"},"status":"Advance l1 and tail."}'::jsonb),
('merge-two-sorted', 6, 'Append 1 from l2', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"current"},{"value":4,"state":"default"}],"pointers":{"l1":1},"hashmap":{"result":"1->1","l2_idx":"1"},"status":"l2[0]=1 < l1[1]=2 — take l2."}'::jsonb),
('merge-two-sorted', 7, 'Append 2 from l1', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":4,"state":"current"}],"pointers":{"l1":2},"hashmap":{"result":"1->1->2","l2_idx":"1"},"status":"2 < 3 — take l1."}'::jsonb),
('merge-two-sorted', 8, 'Append 3 from l2', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":4,"state":"current"}],"pointers":{"l1":2},"hashmap":{"result":"1->1->2->3","l2_idx":"2"},"status":"3 < 4 — take l2."}'::jsonb),
('merge-two-sorted', 9, 'Tie at 4: take l1', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":4,"state":"visited"}],"pointers":{"l1":3},"hashmap":{"result":"1->1->2->3->4","l2_idx":"2"},"status":"Advance l1 past end."}'::jsonb),
('merge-two-sorted', 10, 'Splice remaining l2 (4)', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":4,"state":"visited"}],"pointers":{},"hashmap":{"result":"1->1->2->3->4->4"},"status":"Attach remainder of l2 as a single step."}'::jsonb),
('merge-two-sorted', 11, 'Termination', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":4,"state":"visited"}],"pointers":{},"hashmap":{"done":"true"},"status":"Both lists exhausted."}'::jsonb),
('merge-two-sorted', 12, 'Result', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":4,"state":"visited"}],"pointers":{},"hashmap":{"answer":"1->1->2->3->4->4"},"status":"dummy.next is the merged head."}'::jsonb),
('merge-two-sorted', 13, 'Return + Recap', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"}],"pointers":{},"hashmap":{"time":"O(n+m)","space":"O(1)"},"status":"Dummy-head technique simplifies edge cases."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('reorder-list', 1, 'Problem Setup', '{"type":"linked-list","nodes":[{"value":1,"state":"default"},{"value":2,"state":"default"},{"value":3,"state":"default"},{"value":4,"state":"default"}],"pointers":{"head":0},"hashmap":{"goal":"L0 Ln L1 Ln-1 ..."},"status":"Reorder in place: first, last, second, second-to-last, ..."}'::jsonb),
('reorder-list', 2, 'Approach', '{"type":"linked-list","nodes":[{"value":1,"state":"default"},{"value":2,"state":"default"},{"value":3,"state":"default"},{"value":4,"state":"default"}],"pointers":{},"hashmap":{"phases":"mid, reverse, merge"},"status":"1) find middle, 2) reverse second half, 3) weave two halves."}'::jsonb),
('reorder-list', 3, 'Complexity', '{"type":"linked-list","nodes":[{"value":1,"state":"default"}],"pointers":{},"hashmap":{"time":"O(n)","space":"O(1)"},"status":"Three linear passes, no extra memory."}'::jsonb),
('reorder-list', 4, 'Phase 1 — slow/fast', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"current"},{"value":3,"state":"default"},{"value":4,"state":"default"}],"pointers":{"slow":1,"fast":3},"hashmap":{},"status":"Slow stops at index 1 — end of first half."}'::jsonb),
('reorder-list', 5, 'Split into [1,2] and [3,4]', '{"type":"linked-list","nodes":[{"value":1,"state":"default"},{"value":2,"state":"default"},{"value":3,"state":"highlighted"},{"value":4,"state":"highlighted"}],"pointers":{"first":0,"second":2},"hashmap":{"left":"1->2","right":"3->4"},"status":"Cut slow.next = null."}'::jsonb),
('reorder-list', 6, 'Phase 2 — reverse [3,4]', '{"type":"linked-list","nodes":[{"value":1,"state":"default"},{"value":2,"state":"default"},{"value":4,"state":"highlighted"},{"value":3,"state":"highlighted"}],"pointers":{"first":0,"second":2},"hashmap":{"right_reversed":"4->3"},"status":"Standard prev/curr reversal of second half."}'::jsonb),
('reorder-list', 7, 'Phase 3 — splice 1 -> 4', '{"type":"linked-list","nodes":[{"value":1,"state":"current"},{"value":4,"state":"current"},{"value":2,"state":"default"},{"value":3,"state":"highlighted"}],"pointers":{"first":0,"second":1},"hashmap":{"partial":"1->4->..."},"status":"Insert 4 after 1 by rewiring next pointers."}'::jsonb),
('reorder-list', 8, 'Splice 2 -> 3', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":4,"state":"visited"},{"value":2,"state":"current"},{"value":3,"state":"current"}],"pointers":{"first":2,"second":3},"hashmap":{"partial":"1->4->2->3"},"status":"Insert 3 after 2."}'::jsonb),
('reorder-list', 9, 'Both halves exhausted', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":4,"state":"visited"},{"value":2,"state":"visited"},{"value":3,"state":"visited"}],"pointers":{},"hashmap":{"loop":"exit"},"status":"No more nodes to weave."}'::jsonb),
('reorder-list', 10, 'Termination', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":4,"state":"visited"},{"value":2,"state":"visited"},{"value":3,"state":"visited"}],"pointers":{},"hashmap":{"done":"true"},"status":"List reordered in place."}'::jsonb),
('reorder-list', 11, 'Result', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":4,"state":"visited"},{"value":2,"state":"visited"},{"value":3,"state":"visited"}],"pointers":{},"hashmap":{"answer":"1->4->2->3"},"status":"Final order achieved."}'::jsonb),
('reorder-list', 12, 'Return + Recap', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"}],"pointers":{},"hashmap":{"time":"O(n)","space":"O(1)"},"status":"mid + reverse + weave — a classic 3-phase LL pattern."}'::jsonb);
INSERT INTO public."PGcode_interactive_dry_runs" (problem_id, step_number, title, visual_state_data) VALUES
('reverse-linked-list', 1, 'Problem Setup', '{"type":"linked-list","nodes":[{"value":1,"state":"default"},{"value":2,"state":"default"},{"value":3,"state":"default"},{"value":4,"state":"default"},{"value":5,"state":"default"}],"pointers":{"head":0},"hashmap":{"goal":"5->4->3->2->1"},"status":"Reverse the entire linked list in place."}'::jsonb),
('reverse-linked-list', 2, 'Approach', '{"type":"linked-list","nodes":[{"value":1,"state":"default"}],"pointers":{},"hashmap":{"approach":"iterative prev/curr"},"status":"Walk once, flipping each next pointer."}'::jsonb),
('reverse-linked-list', 3, 'Complexity', '{"type":"linked-list","nodes":[{"value":1,"state":"default"}],"pointers":{},"hashmap":{"time":"O(n)","space":"O(1)"},"status":"Constant extra memory."}'::jsonb),
('reverse-linked-list', 4, 'Init prev=null, curr=head', '{"type":"linked-list","nodes":[{"value":1,"state":"current"},{"value":2,"state":"default"},{"value":3,"state":"default"},{"value":4,"state":"default"},{"value":5,"state":"default"}],"pointers":{"prev":-1,"curr":0},"hashmap":{},"status":"prev virtual null, curr at 1."}'::jsonb),
('reverse-linked-list', 5, 'Flip 1: next=2, 1.next=null', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"current"},{"value":3,"state":"default"},{"value":4,"state":"default"},{"value":5,"state":"default"}],"pointers":{"prev":0,"curr":1},"hashmap":{"reversed":"1"},"status":"Store next=2, set 1.next=prev, advance."}'::jsonb),
('reverse-linked-list', 6, 'Flip 2: 2.next=1', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":3,"state":"current"},{"value":4,"state":"default"},{"value":5,"state":"default"}],"pointers":{"prev":1,"curr":2},"hashmap":{"reversed":"2->1"},"status":"Advance prev and curr."}'::jsonb),
('reverse-linked-list', 7, 'Flip 3: 3.next=2', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":3,"state":"visited"},{"value":4,"state":"current"},{"value":5,"state":"default"}],"pointers":{"prev":2,"curr":3},"hashmap":{"reversed":"3->2->1"},"status":"Continue."}'::jsonb),
('reverse-linked-list', 8, 'Flip 4: 4.next=3', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":3,"state":"visited"},{"value":4,"state":"visited"},{"value":5,"state":"current"}],"pointers":{"prev":3,"curr":4},"hashmap":{"reversed":"4->3->2->1"},"status":"One more to go."}'::jsonb),
('reverse-linked-list', 9, 'Flip 5: 5.next=4', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":3,"state":"visited"},{"value":4,"state":"visited"},{"value":5,"state":"visited"}],"pointers":{"prev":4,"curr":-1},"hashmap":{"reversed":"5->4->3->2->1"},"status":"curr becomes null."}'::jsonb),
('reverse-linked-list', 10, 'Loop exit (curr=null)', '{"type":"linked-list","nodes":[{"value":1,"state":"visited"},{"value":2,"state":"visited"},{"value":3,"state":"visited"},{"value":4,"state":"visited"},{"value":5,"state":"visited"}],"pointers":{"prev":4,"curr":-1},"hashmap":{"newHead":"5"},"status":"prev now references the new head."}'::jsonb),
('reverse-linked-list', 11, 'Termination', '{"type":"linked-list","nodes":[{"value":5,"state":"visited"},{"value":4,"state":"visited"},{"value":3,"state":"visited"},{"value":2,"state":"visited"},{"value":1,"state":"visited"}],"pointers":{},"hashmap":{"done":"true"},"status":"All pointers flipped."}'::jsonb),
('reverse-linked-list', 12, 'Result', '{"type":"linked-list","nodes":[{"value":5,"state":"visited"},{"value":4,"state":"visited"},{"value":3,"state":"visited"},{"value":2,"state":"visited"},{"value":1,"state":"visited"}],"pointers":{},"hashmap":{"answer":"5->4->3->2->1"},"status":"Return prev."}'::jsonb),
('reverse-linked-list', 13, 'Return + Recap', '{"type":"linked-list","nodes":[{"value":5,"state":"visited"}],"pointers":{},"hashmap":{"time":"O(n)","space":"O(1)"},"status":"Iterative prev/curr pointer reversal."}'::jsonb);
