-- Expanded dry runs: Batch 3 — Trees, Tries, Linked Lists (22 problems, 10-13 frames each)
-- Preserves existing renderer types: 18 tree, 4 linked-list.
BEGIN;

-- ============================================================
-- TREE-TYPE PROBLEMS (18)
-- ============================================================

-- balanced-binary-tree on [3,9,20,null,null,15,7]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'balanced-binary-tree';

-- binary-tree-right-side on [1,2,3,null,5,null,4]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'binary-tree-right-side';

-- combination-sum-ii: candidates=[2,5,2,1,2], target=5
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'combination-sum-ii';

-- construct-from-preorder-inorder: preorder=[3,9,20,15,7], inorder=[9,3,15,20,7]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'construct-from-preorder-inorder';

-- diameter-binary-tree on [1,2,3,4,5]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'diameter-binary-tree';

-- invert-binary-tree on [4,2,7,1,3,6,9]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'invert-binary-tree';

-- kth-smallest-bst: root=[5,3,6,2,4,null,null,1], k=3
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'kth-smallest-bst';

-- letter-combinations: digits="23"
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'letter-combinations';

-- level-order-traversal on [3,9,20,null,null,15,7]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'level-order-traversal';

-- longest-word-dictionary: words=["w","wo","wor","worl","world"] (trie)
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'longest-word-dictionary';

-- lowest-common-ancestor BST: root=[6,2,8,0,4,7,9], p=2, q=8
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'lowest-common-ancestor';

-- max-depth-binary-tree on [3,9,20,null,null,15,7]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'max-depth-binary-tree';

-- palindrome-partitioning: s="aab"
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'palindrome-partitioning';

-- replace-words: dict=["cat","bat","rat"], sentence="the cattle was rattled by the battery"
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'replace-words';

-- same-tree: p=q=[1,2,3]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'same-tree';

-- search-suggestions-system: products=["mobile","moneypot","monitor"], searchWord="mou"
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'search-suggestions-system';

-- subtree-of-another: root=[3,4,5,1,2], subRoot=[4,1,2]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'subtree-of-another';

-- validate-bst: root=[5,1,4,null,null,3,6]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'validate-bst';

-- ============================================================
-- LINKED-LIST-TYPE PROBLEMS (4)
-- ============================================================

-- linked-list-cycle: [3,2,0,-4] cycle at index 1
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'linked-list-cycle';

-- merge-two-sorted: [1,2,4] + [1,3,4]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'merge-two-sorted';

-- reorder-list: [1,2,3,4]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'reorder-list';

-- reverse-linked-list: [1,2,3,4,5]
DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id = 'reverse-linked-list';

COMMIT;

SELECT problem_id, COUNT(*) AS steps FROM public."PGcode_interactive_dry_runs"
WHERE problem_id IN (
  'balanced-binary-tree','binary-tree-right-side','combination-sum-ii','construct-from-preorder-inorder',
  'diameter-binary-tree','invert-binary-tree','kth-smallest-bst','letter-combinations',
  'level-order-traversal','longest-word-dictionary','lowest-common-ancestor','max-depth-binary-tree',
  'palindrome-partitioning','replace-words','same-tree','search-suggestions-system',
  'subtree-of-another','validate-bst',
  'linked-list-cycle','merge-two-sorted','reorder-list','reverse-linked-list'
)
GROUP BY problem_id ORDER BY problem_id;
